export type ImageModelV3 = {
  readonly specificationVersion: 'v3';
  readonly provider: string;
  readonly modelId: string;

  /**
   * Limit of how many images can be generated in a single API call.
   * Can be a number, undefined, or async function.
   */
  readonly maxImagesPerCall: 
    | number 
    | undefined 
    | ((options: { modelId: string }) => PromiseLike<number | undefined> | number | undefined);

  doGenerate(options: ImageModelV3CallOptions): PromiseLike<{
    /**
     * Generated images as base64 encoded strings or Uint8Array.
     * Return format matches what API provides (no unnecessary conversion).
     */
    images: Array<string> | Array<Uint8Array>;

    /**
     * Warnings for unsupported features
     */
    warnings: Array<SharedV3Warning>;

    /**
     * Provider-specific metadata structure
     */
    providerMetadata?: {
      [providerName: string]: {
        images: JSONArray;
      } & JSONValue;
    };

    /**
     * Response info for telemetry
     */
    response: {
      timestamp: Date;
      modelId: string;
      headers: Record<string, string> | undefined;
    };

    /**
     * Optional token usage for image generation
     */
    usage?: ImageModelV3Usage;
  }>;
};
