export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | 'retro-classic'
  | (string & {});

export interface PixelArtImageSettings {
  /**
   * The size of the generated image (e.g., "256x256", "512x512", "1024x1024").
   * This can be overridden per-call via the `size` option in `generateImage`.
   */
  size?: string;

  /**
   * The artistic style of the pixel art.
   * - "pixel": Classic pixel art style
   * - "retro": Retro-inspired style reminiscent of early computer graphics
   * - "8bit": 8-bit video game aesthetic
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * The pixel density of the generated image.
   * Higher values produce finer pixel grids. Typical range: 1–64.
   */
  pixelDensity?: number;

  /**
   * Override the maximum number of images generated per API call.
   * Defaults to 4.
   */
  maxImagesPerCall?: number;
}

