import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  combineHeaders,
  createJsonResponseHandler,
  FetchFunction,
  lazySchema,
  postJsonToApi,
  Resolvable,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelArtFailedResponseHandler } from './pixelart-error';
import {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';

export interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      images: z.array(
        z.object({
          base64: z.string(),
        }),
      ),
      model: z.string().nullish(),
      created: z.number().nullish(),
    }),
  ),
);

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return this.settings.maxImagesPerCall ?? 4;
  }

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly settings: PixelArtImageSettings,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n = 1,
      size,
      aspectRatio,
      seed,
      providerOptions,
      headers,
      abortSignal,
      files,
      mask,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    // PixelArt API does not support image editing
    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details:
          'PixelArt does not support image editing. The `files` option is ignored.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details:
          'PixelArt does not support mask-based image editing. The `mask` option is ignored.',
      });
    }

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support the `aspectRatio` option. Use `size` instead.',
      });
    }

    // Resolve the effective image size: call-level size overrides settings-level size
    const effectiveSize = size ?? this.settings.size;

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { responseHeaders, value: response } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        ...(effectiveSize != null ? { size: effectiveSize } : {}),
        ...(seed != null ? { seed } : {}),
        ...(this.settings.style != null ? { style: this.settings.style } : {}),
        ...(this.settings.pixelDensity != null
          ? { pixel_density: this.settings.pixelDensity }
          : {}),
        ...(providerOptions?.pixelart != null ? providerOptions.pixelart : {}),
      },
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.images.map(image => image.base64),
      warnings,
      providerMetadata: {
        pixelart: {
          images: response.images.map(() => ({
            model: response.model ?? undefined,
            created: response.created ?? undefined,
          })),
        },
      },
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

import { ImageModelV3 } from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { VERSION } from './version';
import { PixelArtImageModel } from './pixelart-image-model';
import {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';

export interface PixelArtProvider {
  /**
   * Creates a PixelArt image generation model.
   */
  image(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;

  /**
   * Alias for `image()`.
   */
  imageModel(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;
}

export interface PixelArtProviderSettings {
  /**
   * Base URL for the PixelArt API.
   * Defaults to `https://api.pixelart.ai/v1`.
   */
  baseURL?: string;

  /**
   * API key for authenticating with the PixelArt API.
   * Defaults to the `PIXELART_API_KEY` environment variable.
   */
  apiKey?: string;

  /**
   * Custom headers to include in every request.
   */
  headers?: Record<string, string | undefined>;

  /**
   * Custom fetch implementation. Useful for middleware, proxies, or testing.
   */
  fetch?: FetchFunction;
}

/**
 * Create a PixelArt provider instance.
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(options.baseURL) ?? 'https://api.pixelart.ai/v1';

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (
    modelId: PixelArtImageModelId,
    settings: PixelArtImageSettings = {},
  ) =>
    new PixelArtImageModel(modelId, settings, {
      provider: 'pixelart',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const provider: PixelArtProvider = {
    image: createImageModel,
    imageModel: createImageModel,
  };

  return provider;
}

/**
 * Default PixelArt provider instance.
 */
export const pixelart = createPixelArt();

